/* ── Recruiter Banner ── */
@media print {
    #recruiter-banner, #banner-spacer { display: none !important; }
}

#recruiter-banner {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 9999;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

#banner-strip {
    background: rgba(255,255,255,0.88);
    backdrop-filter: blur(20px) saturate(160%);
    -webkit-backdrop-filter: blur(20px) saturate(160%);
    border-bottom: 1px solid rgba(0,0,0,0.07);
    box-shadow: 0 1px 6px rgba(0,0,0,0.04);
    height: 40px;
    padding: 0 24px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    cursor: default;
    user-select: none;
}

#banner-cta {
    font-size: 12.5px;
    font-weight: 500;
    color: #6366f1;
    letter-spacing: 0.2px;
    display: flex;
    align-items: center;
    gap: 6px;
    transition: color 0.15s;
}
#recruiter-banner:hover #banner-cta { color: #4f46e5; }

#banner-chevron {
    position: absolute;
    right: 22px;
    top: 50%;
    transform: translateY(-50%);
    font-size: 16px;
    color: #94a3b8;
    line-height: 1;
    transition: transform 0.22s cubic-bezier(0.16,1,0.3,1), color 0.15s;
}
#recruiter-banner:hover #banner-chevron {
    transform: translateY(-50%) rotate(180deg);
    color: #6366f1;
}

#banner-panel {
    background: rgba(255,255,255,0.97);
    backdrop-filter: blur(20px) saturate(160%);
    -webkit-backdrop-filter: blur(20px) saturate(160%);
    max-height: 0;
    overflow: hidden;
    transition: max-height 0.24s cubic-bezier(0.16,1,0.3,1);
    border-bottom: 1px solid rgba(0,0,0,0.07);
    box-shadow: 0 10px 28px rgba(0,0,0,0.06);
}
#recruiter-banner:hover #banner-panel { max-height: 33vh; }

#banner-inner {
    padding: 12px 24px 14px;
    height: calc(33vh - 26px);
    display: flex;
    flex-direction: column;
    gap: 10px;
    box-sizing: border-box;
}

#banner-toolbar {
    display: flex;
    align-items: center;
    gap: 7px;
    flex-shrink: 0;
}

.blang-btn {
    background: transparent;
    border: 1px solid #cbd5e1;
    color: #64748b;
    padding: 3px 12px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 10.5px;
    font-weight: 600;
    letter-spacing: 0.4px;
    transition: border-color 0.12s, color 0.12s, background 0.12s;
    font-family: inherit;
}
.blang-btn:hover { border-color: #6366f1; color: #6366f1; }
.blang-btn.active { background: #6366f1; border-color: #6366f1; color: #fff; }

#banner-copy-btn {
    margin-left: auto;
    background: transparent;
    border: 1px solid #cbd5e1;
    color: #64748b;
    padding: 4px 14px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 11px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 5px;
    transition: border-color 0.12s, color 0.12s, background 0.12s;
    font-family: inherit;
}
#banner-copy-btn:hover { border-color: #6366f1; color: #6366f1; }
#banner-copy-btn.copied { border-color: #16a34a; color: #16a34a; }

#banner-prompt-area {
    flex: 1;
    overflow-y: auto;
    font-size: 11px;
    line-height: 1.62;
    white-space: pre-wrap;
    font-family: 'SF Mono', 'Fira Code', 'Courier New', monospace;
    background: #f8fafc;
    border: 1px solid #e2e8f0;
    border-radius: 6px;
    padding: 10px 14px;
    color: #475569;
    scrollbar-width: thin;
    scrollbar-color: #cbd5e1 transparent;
}
#banner-prompt-area::-webkit-scrollbar { width: 3px; }
#banner-prompt-area::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 2px; }

#banner-spacer {
    height: 40px;
    transition: height 0.24s cubic-bezier(0.16,1,0.3,1);
}
#recruiter-banner:hover + #banner-spacer { height: calc(40px + 33vh); }

