/* ── Recruiter Banner ── */
@media print {
    #recruiter-banner, #banner-spacer { display: none !important; }
}

#recruiter-banner {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 9999;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

#banner-strip {
    background: linear-gradient(135deg, #0d1b2a 0%, #1b2a3b 60%, #0f3460 100%);
    color: #fff;
    padding: 10px 20px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    border-bottom: 2px solid #e94560;
    user-select: none;
    transition: background 0.2s;
}
#banner-strip:hover { background: linear-gradient(135deg, #162030 0%, #22334a 60%, #1a4a80 100%); }

#banner-strip-left { display: flex; align-items: center; gap: 10px; }
#banner-strip-icon { font-size: 18px; }
#banner-strip-title { font-weight: 700; font-size: 12px; letter-spacing: 1.5px; color: #fff; }
#banner-strip-sub { font-size: 11px; opacity: 0.55; margin-left: 4px; }
#banner-strip-right { display: flex; align-items: center; gap: 8px; }
#banner-hint { font-size: 10px; opacity: 0.5; letter-spacing: 0.5px; }
#banner-arrow {
    font-size: 12px;
    display: inline-block;
    transition: transform 0.35s cubic-bezier(.4,0,.2,1);
    color: #e94560;
}

#banner-panel {
    background: #0d1b2a;
    max-height: 0;
    overflow: hidden;
    transition: max-height 0.42s cubic-bezier(.4,0,.2,1);
    border-bottom: 2px solid #e94560;
}
#banner-panel.open { max-height: 33vh; }

#banner-inner {
    padding: 14px 20px 16px;
    height: calc(33vh - 36px);
    display: flex;
    flex-direction: column;
    gap: 10px;
    box-sizing: border-box;
}

#banner-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
}
#banner-toolbar-label {
    font-size: 10px;
    letter-spacing: 1px;
    color: #7a9bbf;
    text-transform: uppercase;
    margin-right: 4px;
}

.blang-btn {
    background: transparent;
    border: 1px solid #e94560;
    color: #c0c8d8;
    padding: 4px 13px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.5px;
    transition: background 0.15s, color 0.15s;
    font-family: inherit;
}
.blang-btn:hover { background: rgba(233,69,96,0.15); }
.blang-btn.active { background: #e94560; color: #fff; border-color: #e94560; }

#banner-copy-btn {
    margin-left: auto;
    background: #e94560;
    border: none;
    color: #fff;
    padding: 5px 16px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 12px;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 6px;
    transition: background 0.15s, transform 0.1s;
    font-family: inherit;
}
#banner-copy-btn:hover { background: #c73352; }
#banner-copy-btn:active { transform: scale(0.97); }
#banner-copy-btn.copied { background: #2e7d52; }

#banner-prompt-area {
    flex: 1;
    overflow-y: auto;
    font-size: 11.5px;
    line-height: 1.65;
    white-space: pre-wrap;
    font-family: 'SF Mono', 'Fira Code', 'Courier New', monospace;
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    padding: 10px 14px;
    color: #a8bdd4;
    scrollbar-width: thin;
    scrollbar-color: #e94560 transparent;
}
#banner-prompt-area::-webkit-scrollbar { width: 4px; }
#banner-prompt-area::-webkit-scrollbar-thumb { background: #e94560; border-radius: 2px; }
